dashboard.definition:
{
  "title": "SplunkGate — Regulator Evidence Pack",
  "description": "Single-shot examiner artifact. Choose your jurisdictional profile and time window; export to PDF for the record.",
  "inputs": {
    "input_time": {
      "type": "input.timerange",
      "title": "Coverage period",
      "options": {"defaultValue": "-30d@d,now", "token": "input_time"}
    },
    "input_jurisdictional_tag": {
      "type": "input.dropdown",
      "title": "Jurisdictional profile",
      "options": {
        "defaultValue": "ALL",
        "token": "input_jurisdictional_tag",
        "items": [
          {"label": "All profiles", "value": "ALL"},
          {"label": "FSI (FFIEC-AIML / SR 26-2)", "value": "FSI"},
          {"label": "HIPAA (Safe Harbor 18)", "value": "HIPAA"},
          {"label": "PCI (PCI-DSS 11.x)", "value": "PCI"},
          {"label": "PUBSEC (NIST AI RMF)", "value": "PUBSEC"}
        ]
      }
    }
  },
  "dataSources": {
    "ds_header_kpis": {
      "type": "ds.search",
      "options": {
        "query": "`splunkgate_data` | stats count as total_decisions, dc(trace_id) as unique_traces, count(eval(explanation!=\"\")) as attested_decisions | eval coverage_label = strftime(relative_time(now(),\"$input_time.earliest$\"),\"%Y-%m-%d\") . \" — \" . strftime(relative_time(now(),\"$input_time.latest$\"),\"%Y-%m-%d\")"
      },
      "name": "ds_header_kpis"
    },
    "ds_nist_rmf_table": {
      "type": "ds.search",
      "options": {
        "query": "| makeresults count=4 | eval _time=now() | streamstats count as row | eval function = case(row=1,\"GOVERN\", row=2,\"MAP\", row=3,\"MEASURE\", row=4,\"MANAGE\"), splunkgate_components = case(row=1,\"S1 middleware policy enforcement; S4 dashboards expose accountability roles\", row=2,\"S2 MCP server enumerates agent boundaries; splunkgate_verdict_history KV-store maps decision context\", row=3,\"S4 eval harness produces precision/recall/F1/ECE; OTel gen_ai.evaluation.result events emit per-decision scores\", row=4,\"S1 model_middleware blocks/redacts; story-mw-08 audit chain threads pre+post trace_ids; story-app-08 RBA closes the loop in ES\"), evidence_query = case(row=1,\"`splunkgate_data` surface=mw_model | stats count\", row=2,\"`splunkgate_data` | stats dc(agent_id) as agents dc(surface) as surfaces\", row=3,\"index=cisco_ai_defense sourcetype=cisco_ai_defense:splunkgate_verdict | stats count\", row=4,\"`splunkgate_data` verdict_label=block | stats count by agent_id\") | table function splunkgate_components evidence_query"
      },
      "name": "ds_nist_rmf_table"
    },
    "ds_eu_article_6_table": {
      "type": "ds.search",
      "options": {
        "query": "| makeresults count=5 | eval _time=now() | streamstats count as row | eval annex_iii_use_case = case(row=1,\"Critical infrastructure (Annex III §2)\", row=2,\"Employment, worker management (Annex III §4)\", row=3,\"Essential private/public services (Annex III §5)\", row=4,\"Law enforcement (Annex III §6)\", row=5,\"Administration of justice + democratic processes (Annex III §8)\"), article_6_trigger = case(row=1,\"Article 6(2) — Annex III listed\", row=2,\"Article 6(2) — Annex III + profiling clause (paragraph 3 last subparagraph)\", row=3,\"Article 6(2) — Annex III\", row=4,\"Article 6(2) — Annex III\", row=5,\"Article 6(2) — Annex III + profiling clause\"), splunkgate_response = case(row=1,\"S1 model_middleware blocks injection attempts; verdicts logged with trace_id for Article 9 risk-management evidence\", row=2,\"S1 PII/PHI redaction; story-app-07 HIPAA panel renders detection counts by Safe Harbor 18 identifier\", row=3,\"All 4 surfaces emit OTel events; story-app-08 RBA escalates HIGH-severity to ES analyst\", row=4,\"Foundation-Sec explainer (or template v1) attaches WHY-string for due-process review\", row=5,\"PCI panel + audit-chain trace_ids satisfy decision-traceability obligations\") | table annex_iii_use_case article_6_trigger splunkgate_response"
      },
      "name": "ds_eu_article_6_table"
    },
    "ds_hipaa_safe_harbor": {
      "type": "ds.search",
      "options": {
        "query": "`splunkgate_data` rule=PHI ($input_jurisdictional_tag$=\"HIPAA\" OR $input_jurisdictional_tag$=\"ALL\") | stats count by surface, agent_id | sort -count | head 18"
      },
      "name": "ds_hipaa_safe_harbor"
    },
    "ds_pci_dss_11x": {
      "type": "ds.search",
      "options": {
        "query": "`splunkgate_data` rule=PCI ($input_jurisdictional_tag$=\"PCI\" OR $input_jurisdictional_tag$=\"ALL\") | stats count by surface, agent_id, severity | sort -count"
      },
      "name": "ds_pci_dss_11x"
    },
    "ds_coverage_footer": {
      "type": "ds.search",
      "options": {
        "query": "| makeresults | eval _time=now() | eval generated = strftime(now(),\"%Y-%m-%d %H:%M:%S %Z\") | eval app_version = \"SplunkGate v1.0.0\" | table app_version generated"
      },
      "name": "ds_coverage_footer"
    }
  },
  "visualizations": {
    "header_kpis": {
      "type": "splunk.table",
      "title": "Coverage scope",
      "description": "Audit period and the count of agent decisions SplunkGate logged.",
      "dataSources": {"primary": "ds_header_kpis"},
      "options": {"rowNumbers": false}
    },
    "nist_rmf_function_table": {
      "type": "splunk.table",
      "title": "NIST AI RMF function mapping",
      "description": "4 functions per NIST AI RMF 1.0 Section 5: GOVERN, MAP, MEASURE, MANAGE. Each row pairs the function with the SplunkGate components that produce evidence + the SPL the examiner can run to verify the claim.",
      "dataSources": {"primary": "ds_nist_rmf_table"},
      "options": {"rowNumbers": false}
    },
    "sr_26_2_quote_panel": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### SR 26-2 footnote 3 (April 2026) — out of named MRM scope\\n\\n> \"Generative AI and agentic AI models are novel and rapidly evolving. As such, they are not within the scope of this guidance. Nonetheless, a banking organization's risk management and governance practices should guide the determination of appropriate governance and controls for any tools, processes, or systems not covered in this document. However, the principles described in this guidance apply to traditional statistical and quantitative models and non-generative, non-agentic AI models.\"\\n\\n_SR 26-2 Attachment, footnote 3, p. 3 — joint Federal Reserve / OCC / FDIC, April 17, 2026._\\n\\n**SplunkGate framing:** SR 26-2 explicitly leaves GenAI / agentic AI out of named MRM scope. Examiners therefore rely on the bank's general risk management and governance practices to evaluate SplunkGate-instrumented agents. Every SplunkGate verdict carries a trace_id, an evaluator chain, and an OTel event — together these constitute the auditable evidence chain the footnote anticipates."
      }
    },
    "eu_ai_act_article_6_mapping": {
      "type": "splunk.table",
      "title": "EU AI Act Article 6 — high-risk classification mapping",
      "description": "Article 6 high-risk classification triggers (Article 6(1) product-safety integration + Article 6(2) Annex III enumeration). High-risk Annex III obligations under Article 6(2) apply from 2 August 2026. SplunkGate decisions can satisfy Article 9 (risk management) evidence obligations.",
      "dataSources": {"primary": "ds_eu_article_6_table"},
      "options": {"rowNumbers": false}
    },
    "hipaa_safe_harbor_18_panel": {
      "type": "splunk.table",
      "title": "HIPAA Safe Harbor 18 — PHI detection counts",
      "description": "Conditional on input_jurisdictional_tag == \"HIPAA\" or \"ALL\". An empty table means EITHER no PHI verdicts in the window OR the current profile gate excluded this panel — check the Jurisdictional profile dropdown above. Cisco AI Defense currently emits PII with HIPAA-relevant entity_types; the PHI row in the ATLAS lookup is forward-compat for an eventual discrete PHI rule.",
      "dataSources": {"primary": "ds_hipaa_safe_harbor"},
      "options": {"rowNumbers": false, "showNoData": true}
    },
    "pci_dss_11x_panel": {
      "type": "splunk.table",
      "title": "PCI DSS 11.x — PCI detection counts",
      "description": "Conditional on input_jurisdictional_tag == \"PCI\" or \"ALL\". An empty table means EITHER no PCI verdicts in the window OR the current profile gate excluded this panel — check the Jurisdictional profile dropdown above. Supports PCI-DSS 4.0 11.x sub-requirements via the persisted KV-store retention of PCI-tagged trace_ids.",
      "dataSources": {"primary": "ds_pci_dss_11x"},
      "options": {"rowNumbers": false, "showNoData": true}
    },
    "export_pdf_action": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Export PDF for examiner record\\n\\n**Browser print → Save as PDF** is the canonical examiner-artifact export path. The legacy `/services/pdfgen/render` endpoint does not natively render Dashboard Studio v2 dashboards on all Splunk tenants — we fall back to the browser to guarantee a clean PDF on any deployment.\\n\\n**How to export:**\\n\\n1. Press **Cmd+P** (macOS) or **Ctrl+P** (Windows/Linux).\\n2. In the print dialog, set **Destination** to **Save as PDF**.\\n3. Set **Layout** to **Landscape** and **Margins** to **None** for the cleanest examiner artifact.\\n4. Save with a filename like `splunkgate-evidence-pack-YYYY-MM-DD.pdf`.\\n\\nThe browser-print path preserves all dashboard content (NIST RMF mapping, SR 26-2 quote, EU AI Act mapping, profile-gated panels, coverage footer) and produces an artifact suitable for the examiner's file."
      }
    },
    "coverage_footer": {
      "type": "splunk.table",
      "title": "Artifact provenance",
      "description": "SplunkGate app version + generation timestamp. Required for the chain of custody on the examiner side.",
      "dataSources": {"primary": "ds_coverage_footer"},
      "options": {"rowNumbers": false}
    }
  },
  "layout": {
    "type": "absolute",
    "options": {"width": 1440, "height": 1700, "backgroundColor": "#0e1a2b"},
    "structure": [
      {"item": "header_kpis", "type": "block", "position": {"x": 0, "y": 0, "w": 1440, "h": 120}},
      {"item": "nist_rmf_function_table", "type": "block", "position": {"x": 0, "y": 140, "w": 720, "h": 280}},
      {"item": "sr_26_2_quote_panel", "type": "block", "position": {"x": 740, "y": 140, "w": 700, "h": 280}},
      {"item": "eu_ai_act_article_6_mapping", "type": "block", "position": {"x": 0, "y": 440, "w": 1440, "h": 280}},
      {"item": "hipaa_safe_harbor_18_panel", "type": "block", "position": {"x": 0, "y": 740, "w": 1440, "h": 280}},
      {"item": "pci_dss_11x_panel", "type": "block", "position": {"x": 0, "y": 1040, "w": 1440, "h": 280}},
      {"item": "export_pdf_action", "type": "block", "position": {"x": 0, "y": 1340, "w": 1440, "h": 200}},
      {"item": "coverage_footer", "type": "block", "position": {"x": 0, "y": 1560, "w": 1440, "h": 120}}
    ]
  },
  "defaults": {
    "dataSources": {
      "ds.search": {"options": {"queryParameters": {"earliest": "$input_time.earliest$", "latest": "$input_time.latest$"}}}
    }
  }
}
